    let errorType = data.error;

    // Wenn error ein Axios-Objekt ist, extrahiere den API-Error
    if (typeof errorType === 'object' && errorType.response && errorType.response.data && errorType.response.data.error) {
      errorType = errorType.response.data.error;
    } else if (typeof errorType === 'object') {
      // Fallback: Nur message und code extrahieren
      errorType = errorType.message || 'unknown';
    }

    if (errorType === 'no_match') {
