const data = $input.item.json;

try {
  if (data.error) {
    let errorMsg = 'unbekannter Fehler';

    // Axios-Error: response.data.error vorhanden?
    if (data.error.response?.data?.error) {
      errorMsg = data.error.response.data.error;
    }
    // Oder message enthält escaped JSON wie "400 - {\"error\":\"invalid date\"}"
    else if (data.error.message) {
      const msg = data.error.message;
      const jsonPart = msg.split(' - ')[1] || msg;
      if (jsonPart.startsWith('{"error":')) {
        try {
          errorMsg = JSON.parse(jsonPart).error;
        } catch (e) {
          errorMsg = jsonPart;
        }
      } else {
        errorMsg = msg;
      }
    }

    // Nutzerfreundliche Übersetzung bekannter MEDSTAR-Fehler
    const friendly = {
      'invalid date': 'Das angegebene Datum ist ungültig oder liegt außerhalb der Öffnungszeiten.',
      'invalid profile': 'Das gewählte Profil ist nicht verfügbar.',
      'invalid type': 'Die Terminart wird nicht angeboten.'
    };

    const displayMsg = friendly[errorMsg] || `Technischer Fehler: ${errorMsg}`;

    return {
      message: `Nächster Termin konnte nicht gefunden werden. ${displayMsg}`,
      status: "error",
      error_type: errorMsg
    };
  }

  // Kein Slot gefunden (kein Error, aber nichts frei)
  if (!data.slot) {
    return {
      message: "Kein freier Termin gefunden. Möchten Sie einen anderen Zeitraum oder eine andere Terminart versuchen?",
      status: "success",
      available: "false"
    };
  }

  // Erfolg: Slot vorhanden
  const slotDate = new Date(data.slot);
  const dateStr = slotDate.toLocaleDateString('de-DE', {
    day: 'numeric',
    month: 'long',
    year: 'numeric'
  });
  const timeStr = slotDate.toLocaleTimeString('de-DE', {
    hour: '2-digit',
    minute: '2-digit'
  });

  return {
    message: `Der nächste freie Termin ist am ${dateStr} um ${timeStr} Uhr für ${data.duration_minutes} Minuten.`,
    status: "success",
    available: "true",
    slot: data.slot,
    duration_minutes: String(data.duration_minutes)
  };

} catch (e) {
  return {
    message: "Unerwarteter Fehler bei der Terminsuche.",
    status: "error",
    error_type: "unexpected"
  };
}

