      'invalid pid': 'Ungültige Patienten-ID.',
      'patient not active': 'Der Patient ist derzeit nicht aktiv.',
      'invalid profile': 'Das Profil ist ungültig.'
    };

    const display = friendly[errorMsg] || `Technischer Fehler: ${errorMsg}`;

    return {
      message: `Nachricht konnte nicht hinterlegt werden. ${display} Die Ordination wird informiert.`,
      status: "error",
      error_type: errorMsg
    };
  }

  // Erfolg: Nachricht hinterlegt (Response: { "success": true })
  return {
    message: "Ihre Nachricht wurde erfolgreich hinterlegt. Die Ordination wird sich bei Ihnen melden. Vielen Dank für Ihren Anruf!",
    status: "success"
  };

} catch (e) {
  return {
    message: "Unerwarteter Fehler beim Hinterlegen der Nachricht.",
    status: "error",
    error_type: "unexpected"
  };
}

const data = $input.item.json;
const webhookData = $node["Node-000: Webhook-ElevenLabs"].json.body;

// 🔒 Kanonische Telefonnummer festlegen
const phone =
  webhookData?.caller_id ||
  webhookData?.phone ||
  data?.phone ||
  null;

try {
  if (data.error) {

    // 👇 Sonderfall: "no unique match" mit JSON im Error-String
    if (
      typeof data.error.message === 'string' &&
      data.error.message.includes('no unique match')
    ) {
      try {
        const jsonStart = data.error.message.indexOf('{');
        const jsonString = data.error.message.slice(jsonStart);
        const parsed = JSON.parse(jsonString);

        return {
          message: "Wir haben mehrere Personen mit dieser Telefonnummer im System. Bitte nennen Sie mir Ihr Geburtsdatum zur eindeutigen Identifikation.",
          status: "error",
          error_type: "multiple_pids",
          count: String(parsed.entries || 2),
          phone: String(phone)
        };
      } catch (e) {
        // fällt unten in generische Error-Behandlung
      }
    }

    let errorType = data.error;

    // Axios-Error sauber extrahieren
    if (
      typeof errorType === 'object' &&
      errorType.response &&
      errorType.response.data &&
      errorType.response.data.error
    ) {
      errorType = errorType.response.data.error;
    } else if (typeof errorType === 'object') {
      errorType = errorType.message || 'unknown';
    }

    if (errorType === 'no_match') {
      return {
        message: "Ihre Telefonnummer ist noch nicht in unserem System hinterlegt. Waren Sie schon einmal bei uns?",
        status: "error",
        error_type: "no_match",
        phone: String(phone)
      };
    }

    if (errorType === 'multiple_pids') {
      return {
        message: "Wir haben mehrere Personen mit dieser Telefonnummer im System. Bitte nennen Sie mir Ihr Geburtsdatum zur eindeutigen Identifikation.",
        status: "error",
        error_type: "multiple_pids",
        count: String(data.count || 2),
        phone: String(phone)
      };
    }

    return {
      message: "Patient konnte nicht identifiziert werden.",
      status: "error",
      error_type: "no_match",
      phone: String(phone)
    };
  }

  // ✅ Success case
  const active = data.active ? true : false;

  // 🛑 Optional hartes Failing, falls Telefonnummer fehlt
  if (!phone) {
    throw new Error("No phone number available for identified patient");
  }

  return {
    message: "Sehr gut, ich habe Sie im System gefunden.",
    status: "success",
    pid: String(data.pid),
    svnr: String(data.svnr),
    active: String(active),
    phone: String(phone)
  };

} catch (e) {
  // Globaler Fallback
  return {
    message: "Patient nicht im System angelegt.",
    status: "error",
    error_type: "no_match",
    phone: String(phone)
  };
}

const data = $input.item.json;

try {
  const pid = data.pid ? String(data.pid) : null;

  // Default-Annahme
  let has_prescriptions = false;
  let message_prescriptions = "Es ist keine Medikation vorhanden.";

  // 👉 Fall: API hat einen Fehler geliefert
  if (data.error) {
    let errorMsg = null;

    // Axios-Response sauber extrahieren
    if (data.error.response?.data?.error) {
      errorMsg = data.error.response.data.error;
    } else if (data.error.message) {
      const msg = data.error.message;
      const jsonPart = msg.split(' - ')[1];
      if (jsonPart && jsonPart.startsWith('{')) {
        try {
          errorMsg = JSON.parse(jsonPart).error;
        } catch {
          errorMsg = msg;
        }
      } else {
        errorMsg = msg;
      }
    }

    // ✅ Fachlich gültiger Zustand: keine Medikamente
    if (errorMsg === 'no prescriptions found' || errorMsg === 'order not possible') {
      return {
        pid,
        has_prescriptions: false,
        message_prescriptions: "Es ist keine Medikation vorhanden."
      };
    }

    // ❌ Echter technischer Fehler
    return {
      pid,
      has_prescriptions: false,
      message_prescriptions: "Medikationen konnten technisch nicht geprüft werden."
    };
  }

  // 👉 Erfolgsfall ohne Error-Objekt
  const prescriptions = Array.isArray(data.prescriptions)
    ? data.prescriptions
    : [];

  if (prescriptions.length > 0) {
    has_prescriptions = true;
    message_prescriptions = "Es ist eine Medikation vorhanden.";
  }

  return {
    pid,
    has_prescriptions,
    message_prescriptions
  };

} catch (e) {
  // Globaler Fallback – lieber klar als falsch
  return {
    pid: data?.pid ? String(data.pid) : null,
    has_prescriptions: false,
    message_prescriptions: "Medikationen konnten nicht geprüft werden."
  };
}
